/**
 * Localized opponent flavor text by (year, nation). Falls back to `fallback` (the bundled
 * static English blurb) for teams absent from the campaign CSV, and to English for locales
 * not yet translated (e.g. pt).
 */
export function opponentBlurb(
  year: number,
  nation: string,
  lang: string,
  fallback?: string,
): string | undefined {
  const loc = OPPONENT_BLURBS[`${year}|${nation}`]
  if (!loc) return fallback
  if (lang === "es") return loc.es || loc.en || fallback
  return loc.en || fallback
}
